CREATE DATABASE IF NOT EXISTS job_tracker;
USE job_tracker;

CREATE TABLE cities(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100) UNIQUE);
CREATE TABLE application_status(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(50) UNIQUE);
CREATE TABLE companies(id INT AUTO_INCREMENT PRIMARY KEY,city_id INT,name VARCHAR(255),website VARCHAR(500),career_url VARCHAR(500),email VARCHAR(255),notes TEXT,FOREIGN KEY(city_id) REFERENCES cities(id));
CREATE TABLE applications(id INT AUTO_INCREMENT PRIMARY KEY,company_id INT,status_id INT,notes TEXT,FOREIGN KEY(company_id) REFERENCES companies(id),FOREIGN KEY(status_id) REFERENCES application_status(id));
